<div class="card content-card mb-4"><div class="card-body p-4"><form method="get" action="<?= e(url('/reports/new-joiners')); ?>" class="row g-3 align-items-end"><div class="col-lg-6"><label class="form-label">Search</label><input type="text" name="q" class="form-control" placeholder="Employee, email, department, or job title..." value="<?= e((string) ($search ?? '')); ?>"></div><div class="col-md-3"><label class="form-label">From</label><input type="date" name="from_date" class="form-control" value="<?= e((string) ($fromDate ?? '')); ?>"></div><div class="col-md-3"><label class="form-label">To</label><input type="date" name="to_date" class="form-control" value="<?= e((string) ($toDate ?? '')); ?>"></div><div class="col-12 d-flex gap-2"><button type="submit" class="btn btn-outline-secondary">Filter</button><a href="<?= e(url('/reports/new-joiners')); ?>" class="btn btn-outline-light border">Reset</a><span class="text-muted small align-self-center ms-auto"><?= e((string) ($scopeLabel ?? '')); ?></span></div></form></div></div>

<div class="card content-card"><div class="card-body p-4"><div class="d-flex justify-content-between align-items-center mb-3"><h5 class="mb-0">New Joiners</h5><span class="badge text-bg-light border"><?= e((string) count($joiners ?? [])); ?> record(s)</span></div><?php if (($joiners ?? []) === []): ?><div class="empty-state">No joiners matched the selected filters.</div><?php else: ?><div class="table-responsive"><table class="table align-middle mb-0"><thead><tr><th>Employee</th><th>Department</th><th>Job Title</th><th>Manager</th><th>Joining Date</th><th>Status</th></tr></thead><tbody><?php foreach ($joiners as $row): ?><tr><td><div class="fw-semibold"><?= e((string) $row['employee_name']); ?></div><div class="small text-muted"><?= e((string) $row['employee_code']); ?></div></td><td><?= e((string) $row['department_name']); ?></td><td><?= e((string) $row['job_title_name']); ?></td><td><?= e((string) $row['manager_name']); ?></td><td><?= e((string) $row['joining_date']); ?></td><td><span class="badge text-bg-light border"><?= e(ucwords(str_replace('_', ' ', (string) $row['employee_status']))); ?></span></td></tr><?php endforeach; ?></tbody></table></div><?php endif; ?></div></div>